41:         super(consumer, kafkaConsumer, threadId, printableTopic);
42: 
43:         this.consumer = consumer;
44: 
45:         offsetRepository = configuration.getOffsetRepository();
46:     }
47: 
48:     @Override
49:     public void commit() {
50:         if (kafkaConsumer.getEndpoint().getConfiguration().isAutoCommitEnable()) {
51:             LOG.info("Auto commitAsync {} from {}", threadId, printableTopic);
52:             consumer.commitAsync();
53:         }
54:     }
55: 
56:     @Override
57:     public void commit(TopicPartition partition) {
58:         Long offset = offsetCache.getOffset(partition);
59:         if (offset == null) {
60:             return;
61:         }
62: 
63:         commitAsync(consumer, partition, offset);
64:     }
65: 
66:     private void commitAsync(Consumer<?, ?> consumer, TopicPartition partition, long partitionLastOffset) {
67:         if (LOG.isDebugEnabled()) {
68:             LOG.debug("Auto commitAsync on stop {} from topic {}", threadId, partition.topic());
69:         }
70: 
71:         final Map<TopicPartition, OffsetAndMetadata> topicPartitionOffsetAndMetadataMap
72:                 = Collections.singletonMap(partition, new OffsetAndMetadata(partitionLastOffset + 1));
73:         consumer.commitAsync(topicPartitionOffsetAndMetadataMap, this::postCommitCallback);
74:     }
75: 
76:     @Override
77:     public KafkaManualCommit getManualCommit(
78:             Exchange exchange, TopicPartition partition, ConsumerRecord<Object, Object> consumerRecord) {
79: 
80:         KafkaManualCommitFactory manualCommitFactory = kafkaConsumer.getEndpoint().getKafkaManualCommitFactory();
81:         if (manualCommitFactory == null) {
82:             manualCommitFactory = new DefaultKafkaManualAsyncCommitFactory();
83:         }
84: 
85:         return getManualCommit(exchange, partition, consumerRecord, manualCommitFactory);
86:     }
87: 
88:     @Override
89:     public void recordOffset(TopicPartition partition, long partitionLastOffset) {
90:         offsetCache.recordOffset(partition, partitionLastOffset);
91:     }
92: 
93:     private void postCommitCallback(Map<TopicPartition, OffsetAndMetadata> committed, Exception exception) {
94:         if (exception == null) {
95:             if (offsetRepository != null) {
96:                 for (var entry : committed.entrySet()) {
97:                     saveStateToOffsetRepository(entry.getKey(), entry.getValue().offset(), offsetRepository);
98:                 }
99:             }
100:         }
101: 
102:         offsetCache.removeCommittedEntries(committed, exception);
103:     }
