37: 
38:     private static final Logger LOG = LoggerFactory.getLogger(AbstractCommitManager.class);
39: 
40:     protected final KafkaConsumer kafkaConsumer;
41:     protected final String threadId;
42:     protected final String printableTopic;
43:     protected final KafkaConfiguration configuration;
44: 
45:     private final Consumer<?, ?> consumer;
46: 
47:     protected AbstractCommitManager(Consumer<?, ?> consumer, KafkaConsumer kafkaConsumer, String threadId,
48:                                     String printableTopic) {
49:         this.consumer = consumer;
50:         this.kafkaConsumer = kafkaConsumer;
51:         this.threadId = threadId;
52:         this.printableTopic = printableTopic;
53:         this.configuration = kafkaConsumer.getEndpoint().getConfiguration();
54:     }
55: 
56:     protected KafkaManualCommit getManualCommit(
57:             Exchange exchange, TopicPartition partition, ConsumerRecord<Object, Object> record,
58:             KafkaManualCommitFactory manualCommitFactory) {
59: 
60:         StateRepository<String, String> offsetRepository = configuration.getOffsetRepository();
61:         long commitTimeoutMs = configuration.getCommitTimeoutMs();
62: 
63:         KafkaManualCommitFactory.CamelExchangePayload camelExchangePayload = new KafkaManualCommitFactory.CamelExchangePayload(
64:                 exchange, consumer, threadId, offsetRepository);
65:         KafkaManualCommitFactory.KafkaRecordPayload kafkaRecordPayload = new KafkaManualCommitFactory.KafkaRecordPayload(
66:                 partition,
67:                 record.offset(), commitTimeoutMs);
68: 
69:         return manualCommitFactory.newInstance(camelExchangePayload, kafkaRecordPayload, this);
70:     }
71: 
72:     @Override
73:     public KafkaManualCommit getManualCommit(
74:             Exchange exchange, TopicPartition partition, ConsumerRecord<Object, Object> consumerRecord) {
75: 
76:         KafkaManualCommitFactory manualCommitFactory = kafkaConsumer.getEndpoint().getKafkaManualCommitFactory();
77:         if (manualCommitFactory == null) {
78:             manualCommitFactory = new DefaultKafkaManualCommitFactory();
79:         }
80: 
81:         return getManualCommit(exchange, partition, consumerRecord, manualCommitFactory);
82:     }
