84:     @Override
85:     public void forceCommit(TopicPartition partition, long partitionLastOffset) {
86:         if (LOG.isDebugEnabled()) {
87:             LOG.debug("Forcing commitSync {} [topic: {} partition: {} offset: {}]", threadId, partition.topic(),
88:                     partition.partition(), partitionLastOffset);
89:         }
90: 
91:         long timeout = configuration.getCommitTimeoutMs();
92:         consumer.commitSync(
93:                 Collections.singletonMap(partition, new OffsetAndMetadata(partitionLastOffset + 1)),
94:                 Duration.ofMillis(timeout));
95:     }
