97:     protected void saveStateToOffsetRepository(
98:             TopicPartition partition, long partitionLastOffset,
99:             StateRepository<String, String> offsetRepository) {
100: 
101:         if (LOG.isDebugEnabled()) {
102:             LOG.debug("Saving offset repository state {} [topic: {} partition: {} offset: {}]", threadId, partition.topic(),
103:                     partition.partition(),
104:                     partitionLastOffset);
105:         }
106:         offsetRepository.setState(serializeOffsetKey(partition), serializeOffsetValue(partitionLastOffset));
107:     }
