{"meta": null, "content": [{"type": "text", "text": "{"content":"1: /*\n2:  * Licensed to the Apache Software Foundation (ASF) under one or more\n3:  * contributor license agreements. See the NOTICE file distributed with\n4:  * this work for additional information regarding copyright ownership.\n5:  * The ASF licenses this file to You under the Apache License, Version 2.0\n6:  * (the \"License\"); you may not use this file except in compliance with\n7:  * the License. You may obtain a copy of the License at\n8:  *\n9:  *    http://www.apache.org/licenses/LICENSE-2.0\n10:  *\n11:  * Unless required by applicable law or agreed to in writing, software\n12:  * distributed under the License is distributed on an \"AS IS\" BASIS,\n13:  * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n14:  * See the License for the specific language governing permissions and\n15:  * limitations under the License.\n16:  */\n17: package kafka.examples;\n18: \n19: import org.apache.kafka.clients.consumer.ConsumerConfig;\n20: import org.apache.kafka.clients.consumer.ConsumerRebalanceListener;\n21: import org.apache.kafka.clients.consumer.ConsumerRecord;\n22: import org.apache.kafka.clients.consumer.ConsumerRecords;\n23: import org.apache.kafka.clients.consumer.KafkaConsumer;\n24: import org.apache.kafka.clients.consumer.NoOffsetForPartitionException;\n25: import org.apache.kafka.clients.consumer.OffsetOutOfRangeException;\n26: import org.apache.kafka.common.KafkaException;\n27: import org.apache.kafka.common.TopicPartition;\n28: import org.apache.kafka.common.errors.AuthorizationException;\n29: import org.apache.kafka.common.errors.RecordDeserializationException;\n30: import org.apache.kafka.common.errors.UnsupportedVersionException;\n31: import org.apache.kafka.common.serialization.IntegerDeserializer;\n32: import org.apache.kafka.common.serialization.StringDeserializer;\n33: \n34: import java.time.Duration;\n35: import java.util.Collection;\n36: import java.util.Optional;\n37: import java.util.Properties;\n38: import java.util.UUID;\n39: import java.util.concurrent.CountDownLatch;\n40: \n41: import static java.util.Collections.singleton;\n42: \n43: /**\n44:  * A simple consumer thread that subscribes to a topic, fetches new records and prints them.\n45:  * The thread does not stop until all records are completed or an exception is raised.\n46:  */\n47: public class Consumer extends Thread implements ConsumerRebalanceListener {\n48:     private final String bootstrapServers;\n49:     private final String topic;\n50:     private final String groupId;\n51:     private final Optional\u003cString\u003e instanceId;\n52:     private final boolean readCommitted;\n53:     private final int numRecords;\n54:     private final CountDownLatch latch;\n55:     private volatile boolean closed;\n56:     private int remainingRecords;\n57: \n58:     public Consumer(String threadName,\n59:                     String bootstrapServers,\n60:                     String topic,\n61:                     String groupId,\n62:                     Optional\u003cString\u003e instanceId,\n63:                     boolean readCommitted,\n64:                     int numRecords,\n65:                     CountDownLatch latch) {\n66:         super(threadName);\n67:         this.bootstrapServers = bootstrapServers;\n68:         this.topic = topic;\n69:         this.groupId = groupId;\n70:         this.instanceId = instanceId;\n71:         this.readCommitted = readCommitted;\n72:         this.numRecords = numRecords;\n73:         this.remainingRecords = numRecords;\n74:         this.latch = latch;\n75:     }\n76: \n77:     @Override\n78:     public void run() {\n79:         // the consumer instance is NOT thread safe\n80:         try (KafkaConsumer\u003cInteger, String\u003e consumer = createKafkaConsumer()) {\n81:             // subscribes to a list of topics to get dynamically assigned partitions\n82:             // this class implements the rebalance listener that