38: import java.util.UUID;
39: import java.util.concurrent.CountDownLatch;
40: 
41: import static java.util.Collections.singleton;
42: 
43: /**
44:  * A simple consumer thread that subscribes to a topic, fetches new records and prints them.
45:  * The thread does not stop until all records are completed or an exception is raised.
46:  */
47: public class Consumer extends Thread implements ConsumerRebalanceListener {
48:     private final String bootstrapServers;
49:     private final String topic;
50:     private final String groupId;
51:     private final Optional<String> instanceId;
52:     private final boolean readCommitted;
53:     private final int numRecords;
54:     private final CountDownLatch latch;
55:     private volatile boolean closed;
56:     private int remainingRecords;
57: 
58:     public Consumer(String threadName,
59:                     String bootstrapServers,
60:                     String topic,
61:                     String groupId,
62:                     Optional<String> instanceId,
63:                     boolean readCommitted,
64:                     int numRecords,
65:                     CountDownLatch latch) {
66:         super(threadName);
67:         this.bootstrapServers = bootstrapServers;
68:         this.topic = topic;
69:         this.groupId = groupId;
70:         this.instanceId = instanceId;
71:         this.readCommitted = readCommitted;
72:         this.numRecords = numRecords;
73:         this.remainingRecords = numRecords;
74:         this.latch = latch;
75:     }
76: 
77:     @Override
78:     public void run() {
79:         // the consumer instance is NOT thread safe
80:         try (KafkaConsumer<Integer, String> consumer = createKafkaConsumer()) {
81:             // subscribes to a list of topics to get dynamically assigned partitions
82:             // this class implements the rebalance listener that we pass here to be notified of such events
83:             consumer.subscribe(singleton(topic), this);
84:             Utils.printOut("Subscribed to %s", topic);
85:             while (!closed && remainingRecords > 0) {
86:                 try {
87:                     // if required, poll updates partition assignment and invokes the configured rebalance listener
88:                     // then tries to fetch records sequentially using the last committed offset or auto.offset.reset policy
89:                     // returns immediately if there are records or times out returning an empty record set
90:                     // the next poll must be called within session.timeout.ms to avoid group rebalance
91:                     ConsumerRecords<Integer, String> records = consumer.poll(Duration.ofSeconds(1));
92:                     for (ConsumerRecord<Integer, String> record : records) {
93:                         Utils.maybePrintRecord(numRecords, record);
94:                     }
95:                     remainingRecords -= records.count();
96:                 } catch (AuthorizationException | UnsupportedVersionException
97:                          | RecordDeserializationException e) {
98:                     // we can't recover from these exceptions
99:                     Utils.printErr(e.getMessage());
100:                     shutdown();
101:                 } catch (OffsetOutOfRangeException | NoOffsetForPartitionException e) {
102:                     // invalid or no offset found without auto.reset.policy
103:                     Utils.printOut("Invalid or no offset found, using latest");
104:                     consumer.seekToEnd(e.partitions());
105:                     consumer.commitSync();
106:                 } catch (KafkaException e) {
107:                     // log the exception and try to continue
108:                     Utils.printErr(e.getMessage());
109:                 }
110:             }
111:         } catch (Throwable e) {
112:             Utils.printErr("Unhandled exception");
113:             e.printStackTrace();
114:         }
115:         Utils.printOut("Fetched %d records", numRecords - remainingRecords);
116:         shutdown();
117:     }
118: 
119:     public void shutdown() {
120:         if (!closed) {
121:             closed = true;
122:             latch.countDown();
123:         }
124:     }
125: 
126:     public KafkaConsumer<Integer, String> createKafkaConsumer() {
127:         Properties props = new Properties();
128:         // bootstrap server config is required for consumer to connect to brokers
129:         props.put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, bootstrapServers);
130:         // client id is not required, but it's good to track the source of requests beyond just ip/port
131:         // by allowing a logical application name to be included in server-side request logging
132:         props.put(ConsumerConfig.CLIENT_ID_CONFIG, "client-" + UUID.randomUUID());
133:         // consumer group id is required when we use subscribe(topics) for group management
134:         props.put(ConsumerConfig.GROUP_ID_CONFIG, groupId);
135:         // sets static membership to improve availability (e.g. rolling restart)
136:         instanceId.ifPresent(id -> props.put(ConsumerConfig.GROUP_INSTANCE_ID_CONFIG, id));
137:         // disables auto commit when EOS is enabled, because offsets are committed with the transaction
138:         props.put(ConsumerConfig.ENABLE_AUTO_COMMIT_CONFIG, readCommitted ? "false" : "true");
139:         // key and value are just byte arrays, so we need to set appropriate deserializers
140:         props.put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, IntegerDeserializer.class);
141:         props.put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);
142:         if (readCommitted) {
143:             // skips ongoing and aborted transactions
144:             props.put(ConsumerConfig.ISOLATION_LEVEL_CONFIG, "read_committed");
145:         }
146:         // sets the reset offset policy in case of invalid or no offset
147:         props.put(ConsumerConfig.AUTO_OFFSET_RESET_CONFIG, "earliest");
148:         return new KafkaConsumer<>(props);
149:     }
150: 
151:     @Override
152:     public void onPartitionsRevoked(Collection<TopicPartition> partitions) {
153:         Utils.printOut("Revoked partitions: %s", partitions);
154:         // this can be used to commit pending offsets when using manual commit and EOS is disabled
155:     }
156: 
157:     @Override
158:     public void onPartitionsAssigned(Collection<TopicPartition> partitions) {
159:         Utils.printOut("Assigned partitions: %s", partitions);
160:         // this can be used to read the offsets from an external store or some other initialization
161:     }
162: 
163:     @Override
164:     public void onPartitionsLost(Collection<TopicPartition> partitions) {
165:         Utils.printOut("Lost partitions: %s", partitions);
166:         // this is called when partitions are reassigned before we had a chance to revoke them gracefully
167:         // we can't commit pending offsets because these partitions are probably owned by other consumers already
168:         // nevertheless, we may need to do some other cleanup
169:     }
170: }
