{
  "legacy_consumer_connector_files": {
    "summary": "The old kafka.consumer.ConsumerConnector interface (Scala-era, pre-0.9 Zookeeper-based API) is NOT present in any of the three provided repositories. These repos represent modern versions of Kafka, Flink, and Camel that have already removed or never included the legacy Scala consumer. The closest analog to 'legacy' within the new Java API is ClassicKafkaConsumer, which implements the classic group protocol (pre-KIP-848) and is explicitly labeled 'legacy' in the codebase's own documentation.",
    "files": []
  },
  "new_kafka_consumer_api_files": {
    "kafka_repo": {
      "repo": "github.com/sg-evals/kafka--0753c489",
      "files": [
        {
          "path": "clients/src/main/java/org/apache/kafka/clients/consumer/KafkaConsumer.java",
          "role": "Public facade / entry point",
          "description": "The top-level public class that implements Consumer<K,V>. It does not contain consumer logic itself; instead it delegates all operations to a ConsumerDelegate<K,V> instance (either ClassicKafkaConsumer or AsyncKafkaConsumer) chosen at construction time by ConsumerDelegateCreator based on the group.protocol config."
        },
        {
          "path": "clients/src/main/java/org/apache/kafka/clients/consumer/internals/ConsumerDelegate.java",
          "role": "Internal interface",
          "description": "Extends Consumer<K,V> with a handful of internal methods (clientId(), metricsRegistry(), kafkaConsumerMetrics(), updateAssignmentMetadataIfNeeded()). Both ClassicKafkaConsumer and AsyncKafkaConsumer implement this interface."
        },
        {
          "path": "clients/src/main/java/org/apache/kafka/clients/consumer/internals/ConsumerDelegateCreator.java",
          "role": "Factory / selector",
          "description": "Reads the group.protocol config. If group.protocol=consumer (KIP-848), creates AsyncKafkaConsumer. Otherwise creates ClassicKafkaConsumer. This is the single decision point for which implementation is used."
        },
        {
          "path": "clients/src/main/java/org/apache/kafka/clients/consumer/internals/ClassicKafkaConsumer.java",
          "role": "Classic (legacy group protocol) implementation",
          "description": "Implements ConsumerDelegate<K,V> using the classic consumer group protocol (pre-KIP-848). All network I/O runs on the calling application thread. Offset management is handled by ConsumerCoordinator, which supports both auto-commit (periodic, triggered during poll()) and manual commitSync()/commitAsync()."
        },
        {
          "path": "clients/src/main/java/org/apache/kafka/clients/consumer/internals/AsyncKafkaConsumer.java",
          "role": "New async (KIP-848 group protocol) implementation",
          "description": "Implements ConsumerDelegate<K,V> using the new consumer group protocol (KIP-848). Network I/O runs on a dedicated ConsumerNetworkThread background thread. Offset commits are managed by CommitRequestManager and communicated via an event queue (ApplicationEvent/BackgroundEvent). Uses CompletableFuture for async operations."
        },
        {
          "path": "clients/src/main/java/org/apache/kafka/clients/consumer/internals/ConsumerCoordinator.java",
          "role": "Offset coordinator for ClassicKafkaConsumer",
          "description": "Manages group coordination and offset commits for the classic protocol. Implements auto-commit via maybeAutoCommitOffsetsAsync() (called during poll()) and maybeAutoCommitOffsetsSync() (called on close). Exposes commitOffsetsAsync() and commitOffsetsSync() for manual commits. Tracks in-flight async commits with AtomicInteger inFlightAsyncCommits."
        },
        {
          "path": "clients/src/main/java/org/apache/kafka/clients/consumer/internals/CommitRequestManager.java",
          "role": "Offset commit manager for AsyncKafkaConsumer",
          "description": "Manages offset commits for the new async consumer. Implements RequestManager and MemberStateListener. Queues commit requests as CompletableFuture-backed tasks processed by the ConsumerNetworkThread. Handles auto-commit scheduling, retry logic for retriable errors (StaleMemberEpochException, RetriableException), and offset fetch requests."
        },
        {
          "path": "examples/src/main/java/kafka/examples/Consumer.java",
          "role": "Usage example",
          "description": "Demonstrates the new KafkaConsumer API: subscribe(), poll() loop, commitSync() on offset-out-of-range, and ConsumerRebalanceListener callbacks. Shows enable.auto.commit=false for EOS (read_committed isolation) and enable.auto.commit=true for non-EOS."
        }
      ]
    },
    "camel_repo": {
      "repo": "github.com/sg-evals/camel--1006f047",
      "files": [
        {
          "path": "components/camel-kafka/src/main/java/org/apache/camel/component/kafka/KafkaConsumer.java",
          "role": "Camel consumer component wrapper",
          "description": "Extends Camel's DefaultConsumer. Manages a thread pool of KafkaFetchRecords Runnable tasks (one per topic/partition thread). Implements ResumeAware, HealthCheckAware, ConsumerListenerAware, and Suspendable. Does not directly use the Kafka consumer API; delegates to KafkaFetchRecords."
        },
        {
          "path": "components/camel-kafka/src/main/java/org/apache/camel/component/kafka/KafkaFetchRecords.java",
          "role": "Per-thread Kafka poll loop",
          "description": "Runnable that holds a reference to org.apache.kafka.clients.consumer.Consumer (the new KafkaConsumer API). Runs the poll() loop, manages pause/resume state, and delegates offset commits to a CommitManager instance created by CommitManagers.createCommitManager()."
        },
        {
          "path": "components/camel-kafka/src/main/java/org/apache/camel/component/kafka/DefaultKafkaClientFactory.java",
          "role": "Kafka client factory",
          "description": "Implements KafkaClientFactory. Creates org.apache.kafka.clients.consumer.KafkaConsumer instances (new API) via new KafkaConsumer(kafkaProps). This is the concrete instantiation point of the Kafka consumer within Camel."
        },
        {
          "path": "components/camel-kafka/src/main/java/org/apache/camel/component/kafka/consumer/AbstractCommitManager.java",
          "role": "Base class for Camel commit managers",
          "description": "Abstract base implementing CommitManager. Holds references to the Kafka Consumer, KafkaConsumer (Camel), threadId, and KafkaConfiguration. Provides forceCommit() (calls consumer.commitSync() with timeout), saveStateToOffsetRepository(), and getManualCommit() factory methods."
        },
        {
          "path": "components/camel-kafka/src/main/java/org/apache/camel/component/kafka/consumer/CommitManagers.java",
          "role": "Commit manager factory",
          "description": "Static factory that selects the appropriate CommitManager based on configuration: AsyncCommitManager (manual async or batch), SyncCommitManager (manual sync), CommitToOffsetManager (external offset repository), or NoopCommitManager (Kafka auto-commit enabled, no Camel-level commit needed)."
        },
        {
          "path": "components/camel-kafka/src/main/java/org/apache/camel/component/kafka/consumer/SyncCommitManager.java",
          "role": "Synchronous offset commit manager",
          "description": "Calls consumer.commitSync(offsets, Duration.ofMillis(timeout)) per partition after recording the offset in an OffsetCache. Optionally persists to a StateRepository<String,String> offsetRepository. Used when allowManualCommit=true and factory is DefaultKafkaManualCommitFactory."
        },
        {
          "path": "components/camel-kafka/src/main/java/org/apache/camel/component/kafka/consumer/AsyncCommitManager.java",
          "role": "Asynchronous offset commit manager",
          "description": "Calls consumer.commitAsync(offsets, callback) per partition. The postCommitCallback saves to offsetRepository on success and cleans the OffsetCache. Used when allowManualCommit=true and factory is DefaultKafkaManualAsyncCommitFactory, or when batching=true."
        },
        {
          "path": "components/camel-kafka/src/main/java/org/apache/camel/component/kafka/consumer/CommitToOffsetManager.java",
          "role": "External offset repository commit manager",
          "description": "Does NOT call Kafka's commitSync/commitAsync. Instead, saves offset state to a Camel StateRepository<String,String> (e.g., a file or database). Used when offsetRepository is configured. The commit() method is a NO-OP; only commit(partition) writes to the repository."
        },
        {
          "path": "components/camel-kafka/src/main/java/org/apache/camel/component/kafka/consumer/NoopCommitManager.java",
          "role": "No-op commit manager",
          "description": "All commit methods are NO-OPs. Used when Kafka's own auto-commit (enable.auto.commit=true) is relied upon and no Camel-level commit management is needed. Logs an info message on commit() to indicate auto-commit is delegated to the Kafka consumer."
        }
      ]
    },
    "flink_repo": {
      "repo": "github.com/sg-evals/flink--0cc95fcc",
      "files": [
        {
          "path": "flink-python/pyflink/datastream/connectors/kafka.py",
          "role": "Python FlinkKafkaConsumer wrapper (deprecated)",
          "description": "Python wrapper around the Java FlinkKafkaConsumer. The class FlinkKafkaConsumer is marked deprecated in favor of KafkaSource. The Java Kafka connector (FlinkKafkaConsumer.java) is not present in this repo — it lives in the separate flink-connector-kafka repository. The flink-connectors/ directory in this repo contains only base, datagen, files, and hadoop-compatibility connectors."
        }
      ],
      "note": "The Flink Kafka connector Java source (FlinkKafkaConsumer.java, KafkaSource.java) is maintained in a separate repository (apache/flink-connector-kafka) and is not present in this Flink core repo snapshot."
    }
  },
  "offset_management_behavioral_differences": {
    "overview": "The migration from the legacy ConsumerConnector to the new KafkaConsumer API introduced fundamental changes in offset storage backend, threading model, commit granularity, and error handling. Within the new API itself, there is a further split between ClassicKafkaConsumer (classic group protocol) and AsyncKafkaConsumer (KIP-848 new group protocol).",
    "differences": [
      {
        "dimension": "Offset storage backend",
        "legacy_consumer_connector": "Offsets stored in Apache ZooKeeper under /consumers/<group>/offsets/<topic>/<partition>. ZooKeeper was the source of truth for consumer group state.",
        "new_kafka_consumer_api": "Offsets stored in a special Kafka topic __consumer_offsets on the broker. ZooKeeper is no longer involved in offset management. This is true for both ClassicKafkaConsumer and AsyncKafkaConsumer.",
        "evidence": "ConsumerCoordinator.java sends OffsetCommitRequest to the group coordinator broker. CommitRequestManager.java similarly sends OffsetCommitRequest via the ConsumerNetworkThread."
      },
      {
        "dimension": "Auto-commit mechanism",
        "legacy_consumer_connector": "Auto-commit was handled by a background AutoCommitScheduler thread that periodically committed offsets to ZooKeeper independently of the application thread. The interval was controlled by auto.commit.interval.ms.",
        "new_kafka_consumer_api_classic": "Auto-commit is triggered lazily during poll() calls. ConsumerCoordinator.maybeAutoCommitOffsetsAsync() is called inside the poll() path; it checks a timer and fires commitOffsetsAsync() when the interval expires. There is no separate background thread — the application thread drives commits.",
        "new_kafka_consumer_api_async": "Auto-commit is scheduled by CommitRequestManager on the ConsumerNetworkThread. The application thread enqueues events; the background thread processes them. This decouples commit I/O from the application poll() call.",
        "evidence": "ClassicKafkaConsumer.java line 612: coordinator.maybeAutoCommitOffsetsAsync(time.milliseconds()) called inside poll(). ConsumerCoordinator.java lines 1196-1202: maybeAutoCommitOffsetsAsync() checks timer expiry. CommitRequestManager.java implements RequestManager processed by ConsumerNetworkThread."
      },
      {
        "dimension": "Manual commit API",
        "legacy_consumer_connector": "No explicit manual commit API. The ConsumerConnector.commitOffsets() method committed all offsets for all streams to ZooKeeper synchronously. There was no per-partition granularity or async variant.",
        "new_kafka_consumer_api": "Explicit commitSync(Map<TopicPartition, OffsetAndMetadata>) and commitAsync(Map<TopicPartition, OffsetAndMetadata>, OffsetCommitCallback) with per-partition granularity. commitSync() blocks until the broker acknowledges. commitAsync() returns immediately; the callback is invoked on the next poll().",
        "evidence": "ClassicKafkaConsumer.java lines 745-750: commitSync calls coordinator.commitOffsetsSync() with timeout. Lines 771-774: commitAsync calls coordinator.commitOffsetsAsync(). Camel SyncCommitManager.java line 75: consumer.commitSync(offsets, Duration.ofMillis(timeout)). Camel AsyncCommitManager.java line 73: consumer.commitAsync(offsets, callback)."
      },
      {
        "dimension": "Commit on close behavior",
        "legacy_consumer_connector": "Calling ConsumerConnector.shutdown() triggered a final synchronous commit to ZooKeeper before releasing resources.",
        "new_kafka_consumer_api_classic": "ConsumerCoordinator.maybeAutoCommitOffsetsSync() is called during close() with a timer. If auto-commit is enabled, it performs a final blocking commitSync. If the timer expires before completion, the commit is abandoned with a debug log.",
        "new_kafka_consumer_api_async": "AsyncKafkaConsumer enqueues a CommitOnCloseEvent to the ConsumerNetworkThread, which processes it before the thread shuts down. This ensures pending commits are flushed asynchronously before close completes.",
        "evidence": "ConsumerCoordinator.java lines 1178-1188: maybeAutoCommitOffsetsSync() with WakeupException/InterruptException handling. AsyncKafkaConsumer.java imports CommitOnCloseEvent (line 48)."
      },
      {
        "dimension": "Threading model for commits",
        "legacy_consumer_connector": "A dedicated AutoCommitScheduler background thread performed commits independently. The application thread and commit thread were separate, which could cause race conditions.",
        "new_kafka_consumer_api_classic": "Single-threaded: all network I/O (fetching, committing, heartbeating) happens on the application thread during poll(). The consumer is explicitly NOT thread-safe. Commits are serialized with fetches.",
        "new_kafka_consumer_api_async": "Two-thread model: application thread enqueues ApplicationEvents (including AsyncCommitEvent, CommitEvent); ConsumerNetworkThread dequeues and processes them, sending actual OffsetCommitRequests to the broker. Results are returned via CompletableFuture or BackgroundEvents.",
        "evidence": "AsyncKafkaConsumer.java imports ApplicationEventHandler, ConsumerNetworkThread, AsyncCommitEvent, CommitEvent. ClassicKafkaConsumer.java comment at line 79 of examples/Consumer.java: 'the consumer instance is NOT thread safe'."
      },
      {
        "dimension": "Error handling on commit failure",
        "legacy_consumer_connector": "ZooKeeper commit failures were typically retried silently by the background thread. Application code had limited visibility into commit failures.",
        "new_kafka_consumer_api_classic": "commitSync() throws CommitFailedException or RetriableCommitFailedException on failure. commitAsync() delivers the exception to the OffsetCommitCallback. ConsumerCoordinator tracks in-flight async commits (inFlightAsyncCommits AtomicInteger) and retries on retriable errors.",
        "new_kafka_consumer_api_async": "CommitRequestManager handles StaleMemberEpochException (re-enqueues with updated epoch), RetriableException (retries), and non-retriable errors (completes the CompletableFuture exceptionally). The application receives failures via the future or callback.",
        "evidence": "ConsumerCoordinator.java lines 1185-1188: catches WakeupException/InterruptException during auto-commit sync. CommitRequestManager.java imports StaleMemberEpochException, RetriableCommitFailedException, UnstableOffsetCommitException. Camel AsyncCommitManager.java lines 93-103: postCommitCallback checks exception != null before saving to offsetRepository."
      },
      {
        "dimension": "Offset commit granularity",
        "legacy_consumer_connector": "commitOffsets() committed all consumed offsets for all topic-partitions in the consumer group at once. No per-partition control.",
        "new_kafka_consumer_api": "commitSync() and commitAsync() accept a Map<TopicPartition, OffsetAndMetadata>, allowing per-partition offset commits with arbitrary metadata strings. The no-arg variants commit all current positions. Camel's SyncCommitManager and AsyncCommitManager commit one partition at a time using singletonMap.",
        "evidence": "Camel SyncCommitManager.java lines 72-75: Collections.singletonMap(partition, new OffsetAndMetadata(lastOffset)). Camel AsyncCommitManager.java lines 71-73: singletonMap(partition, new OffsetAndMetadata(partitionLastOffset + 1))."
      },
      {
        "dimension": "External offset repository (Camel-specific)",
        "legacy_consumer_connector": "Not applicable — no equivalent in the old API.",
        "new_kafka_consumer_api_camel": "Camel introduces CommitToOffsetManager as a third offset management strategy: offsets are saved to a Camel StateRepository<String,String> (e.g., a file, database, or in-memory store) instead of being committed to Kafka brokers. The commit() method is a NO-OP; only commit(partition) writes to the repository. This allows offset tracking to survive consumer restarts without relying on Kafka's __consumer_offsets topic.",
        "evidence": "CommitToOffsetManager.java lines 36-53: commit(partition) calls saveStateToOffsetRepository(); commit() is NO-OP. CommitManagers.java lines 53-55: if offsetRepository != null, return new CommitToOffsetManager(...)."
      },
      {
        "dimension": "Offset commit on rebalance",
        "legacy_consumer_connector": "Rebalance handling was opaque; the framework committed offsets automatically before reassigning partitions.",
        "new_kafka_consumer_api_classic": "ConsumerRebalanceListener.onPartitionsRevoked() is called before partitions are reassigned. The application is responsible for committing pending offsets in this callback if using manual commit. ConsumerCoordinator commits offsets during rebalance if auto-commit is enabled.",
        "new_kafka_consumer_api_async": "The new protocol (KIP-848) uses server-side assignment. The ConsumerRebalanceListenerCallbackNeededEvent and ConsumerRebalanceListenerCallbackCompletedEvent events coordinate rebalance callbacks between the application thread and ConsumerNetworkThread.",
        "evidence": "examples/Consumer.java lines 152-168: onPartitionsRevoked() comment 'this can be used to commit pending offsets when using manual commit'. AsyncKafkaConsumer.java imports ConsumerRebalanceListenerCallbackNeededEvent, ConsumerRebalanceListenerCallbackCompletedEvent."
      }
    ]
  },
  "migration_summary": {
    "key_api_change": "The old ConsumerConnector used a push-based message stream model (createMessageStreams() returning KafkaStream<K,V>) with ZooKeeper-backed offsets. The new KafkaConsumer uses a pull-based poll() model with broker-backed offsets in __consumer_offsets.",
    "within_new_api_split": "The new KafkaConsumer API itself has two implementations selected by group.protocol config: ClassicKafkaConsumer (group.protocol=classic, default) preserves backward compatibility with the classic group protocol; AsyncKafkaConsumer (group.protocol=consumer) implements KIP-848 with a dedicated network thread and server-side partition assignment.",
    "camel_abstraction": "Apache Camel adds a CommitManager abstraction layer on top of the Kafka consumer API, offering four strategies: NoopCommitManager (delegate to Kafka auto-commit), SyncCommitManager (manual commitSync per partition), AsyncCommitManager (manual commitAsync per partition), and CommitToOffsetManager (external StateRepository, bypasses Kafka offset storage entirely).",
    "flink_status": "The Flink Kafka connector Java source is not present in the provided flink--0cc95fcc repo snapshot. The Python wrapper (flink-python/pyflink/datastream/connectors/kafka.py) shows FlinkKafkaConsumer is deprecated in favor of KafkaSource, which uses the new KafkaConsumer API internally."
