39:     public ResumeRebalanceListener(String threadId, KafkaConfiguration configuration,
40:                                    CommitManager commitManager, Consumer<?, ?> consumer, ResumeStrategy resumeStrategy) {
41:         this.threadId = threadId;
42:         this.configuration = configuration;
43:         this.commitManager = commitManager;
44: 
45:         resumeAdapter = resumeStrategy.getAdapter(KafkaResumeAdapter.class);
46:         resumeAdapter.setConsumer(consumer);
47:     }
